// src/components/admin/AdminSidebar.js
import React, { useEffect, useState } from "react";
import { List, ListItem, ListItemIcon, ListItemText, Badge } from "@mui/material";
import DashboardIcon from "@mui/icons-material/Dashboard";
import PeopleIcon from "@mui/icons-material/People";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import LocalTaxiIcon from "@mui/icons-material/LocalTaxi";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import PersonIcon from "@mui/icons-material/Person";
import { useNavigate, useLocation } from "react-router-dom";
import axios from "axios";

const API = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function AdminSidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  const [counts, setCounts] = useState({
    users: 0,
    riders: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
  });

  const token = localStorage.getItem("token");
  const headers = { Authorization: `Bearer ${token}` };

  const fetchOverview = async () => {
    try {
      const res = await axios.get(`${API}/api/admin/overview`, { headers });
      setCounts({
        users: res.data.users || 0,
        riders: res.data.riders || 0,
        captains: res.data.captains || 0,
        pendingCaptains: res.data.pendingCaptains || 0,
        rides: res.data.rides || 0,
      });
    } catch (err) {
      console.error("Failed to fetch overview", err);
    }
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  const menuItems = [
    { label: "Dashboard", icon: <DashboardIcon />, path: "/admin-dashboard", count: 0 },
    { label: "Users", icon: <PersonIcon />, path: "/admin/users", count: counts.users },
    { label: "Riders", icon: <VerifiedUserIcon />, path: "/admin/riders", count: counts.riders },
    { label: "Approved Captains", icon: <PeopleIcon />, path: "/admin/captains", count: counts.captains },
    { label: "Pending Captains", icon: <PendingActionsIcon />, path: "/admin/pending-captains", count: counts.pendingCaptains },
    { label: "Rides", icon: <LocalTaxiIcon />, path: "/admin/rides", count: counts.rides },
  ];

  return (
    <List>
      {menuItems.map((item) => (
        <ListItem
          key={item.label}
          button
          selected={location.pathname === item.path}
          onClick={() => navigate(item.path)}
        >
          <ListItemIcon>
            {item.count > 0 ? (
              <Badge badgeContent={item.count} color="primary">
                {item.icon}
              </Badge>
            ) : (
              item.icon
            )}
          </ListItemIcon>
          <ListItemText primary={item.label} />
        </ListItem>
      ))}
    </List>
  );
}
